export function initialize(sentinel, dotNetHelper) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetHelper.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '128px' });

    observer.observe(sentinel);

    return { observer, sentinel };
}

export function dispose(instance) {
    instance.observer.unobserve(instance.sentinel);
    instance.observer.disconnect();
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="d-flex justify-content-center py-3">
                    <div class="spinner-border" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _observerInstance;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infiniteScroll.js");
        }

        // (Re-)attach observer whenever HasMore is true and we don't have an active observer
        if (HasMore && _module is not null && _observerInstance is null)
        {
            _dotNetRef ??= DotNetObjectReference.Create(this);
            _observerInstance = await _module.InvokeAsync<IJSObjectReference>(
                "initialize", _sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore) return;

        _isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _isLoading = false;

        // Tear down the current observer so it can be re-created on the next render
        // if HasMore is still true (the sentinel element will be new after re-render).
        if (_observerInstance is not null && _module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _observerInstance);
            _observerInstance = null;
        }

        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_observerInstance is not null && _module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _observerInstance);
        }

        _observerInstance = null;

        if (_module is not null)
        {
            await _module.DisposeAsync();
        }

        _dotNetRef?.Dispose();
    }
}

